import { defineComponentSlotStyle } from "@yamada-ui/react"

export const breadcrumbStyle = defineComponentSlotStyle({
  base: {
    ellipsis: {
      color: "fg.muted",
    },
    item: {
      alignItems: "center",
      display: "inline-flex",
    },
    link: {
      rounded: "l1",
      textDecoration: "none",
      transitionDuration: "moderate",
      transitionProperty: "common",
    },
    list: {
      alignItems: "center",
      display: "flex",
      wordBreak: "break-word",
    },
    root: {},
    separator: {
      color: "fg.muted",
    },
  },

  variants: {
    plain: {
      link: {
        _notCurrent: {
          color: "fg.muted",
          _hover: {
            color: "fg",
          },
        },
      },
    },
    underline: {
      link: {
        _notCurrent: {
          _hover: {
            textDecoration: "underline",
          },
        },
      },
    },
  },

  sizes: {
    sm: {
      list: {
        fontSize: "sm",
        gap: "1",
      },
    },
    md: {
      list: {
        fontSize: "md",
        gap: "1.5",
      },
    },
    lg: {
      list: {
        fontSize: "lg",
        gap: "2",
      },
    },
  },

  defaultProps: {
    size: "md",
    variant: "plain",
  },
})

export type BreadcrumbStyle = typeof breadcrumbStyle

import { a11y, page, render } from "#test/browser"
import { Breadcrumb } from "./"

describe("<Breadcrumb />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <Breadcrumb.Root>
        <Breadcrumb.Link href="/">1</Breadcrumb.Link>
        <Breadcrumb.Link href="/">2</Breadcrumb.Link>
        <Breadcrumb.Ellipsis />
        <Breadcrumb.Link href="/">4</Breadcrumb.Link>
        <Breadcrumb.Link href="/" currentPage>
          5
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )
  })

  test("sets `displayName` correctly", () => {
    expect(Breadcrumb.Root.displayName).toBe("BreadcrumbRoot")
    expect(Breadcrumb.Link.displayName).toBe("BreadcrumbLink")
    expect(Breadcrumb.Ellipsis.displayName).toBe("BreadcrumbEllipsis")
  })

  test("sets `className` correctly", async () => {
    await render(
      <Breadcrumb.Root data-testid="root">
        <Breadcrumb.Link href="/">Link 1</Breadcrumb.Link>
        <Breadcrumb.Ellipsis data-testid="ellipsis" />
      </Breadcrumb.Root>,
    )

    await expect
      .element(page.getByTestId("root"))
      .toHaveClass("ui-breadcrumb__root")
    await expect
      .element(page.getByText("Link 1"))
      .toHaveClass("ui-breadcrumb__link")
    await expect
      .element(page.getByTestId("ellipsis"))
      .toHaveClass("ui-breadcrumb__ellipsis")
  })

  test("renders HTML tag correctly", async () => {
    await render(
      <Breadcrumb.Root data-testid="root">
        <Breadcrumb.Link href="/">Link 1</Breadcrumb.Link>
        <Breadcrumb.Ellipsis data-testid="ellipsis" />
      </Breadcrumb.Root>,
    )

    expect(page.getByTestId("root").element().tagName).toBe("NAV")
    expect(page.getByText("Link 1").element().tagName).toBe("A")
    expect(page.getByTestId("ellipsis").element().tagName).toBe("svg")
  })

  test("separator property is being passed accurately", async () => {
    await render(
      <Breadcrumb.Root separator="-">
        <Breadcrumb.Link href="/">1</Breadcrumb.Link>
        <Breadcrumb.Link href="/" currentPage>
          2
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )

    const separatorEle = page.getByText("-").element()
    expect(separatorEle).toBeInTheDocument()
  })

  test("currentPage property is being passed accurately", async () => {
    await render(
      <Breadcrumb.Root separator="-">
        <Breadcrumb.Link href="/">1</Breadcrumb.Link>
        <Breadcrumb.Link href="/" currentPage>
          2
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )
    const spanElement = page.getByText("2").element()
    expect(spanElement).toBeInTheDocument()
    expect(spanElement.nodeName.toLowerCase()).toBe("span")
  })

  test("breadcrumb link has its href attribute correctly set", async () => {
    await render(
      <Breadcrumb.Root>
        <Breadcrumb.Link href="#">Link 1</Breadcrumb.Link>
        <Breadcrumb.Link href="#" currentPage>
          Link 2
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )
    const breadcrumbLink = page.getByRole("link", { name: /Link 1/i }).element()
    expect(breadcrumbLink).toHaveAttribute("href", "#")
  })

  test("current page link doesn't have href attribute set", async () => {
    await render(
      <Breadcrumb.Root>
        <Breadcrumb.Link href="#">Link 1</Breadcrumb.Link>
        <Breadcrumb.Link href="#" currentPage>
          Link 2
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )
    const currentPageLink = page.getByText("Link 2").element()
    expect(currentPageLink).not.toHaveAttribute("href")
  })

  test("renders breadcrumbEllipsis correctly", async () => {
    await render(
      <Breadcrumb.Root>
        <Breadcrumb.Link href="#">Link 1</Breadcrumb.Link>
        <Breadcrumb.Ellipsis />
        <Breadcrumb.Link href="#" currentPage>
          Link 3
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )
    await expect.element(page.getByLabelText("Ellipsis")).toBeInTheDocument()
  })

  test("renders breadcrumb correctly with items", async () => {
    const items: Breadcrumb.Item[] = [
      { href: "/", label: "サイヤ人編" },
      { href: "/", label: "ナメック星編" },
      { href: "/", label: "人造人間編" },
      { href: "/", currentPage: true, label: "魔人ブウ編" },
    ]

    await render(<Breadcrumb.Root items={items} />)

    expect(page.getByRole("listitem")).toHaveLength(7)
  })

  test("is correctly truncated", async () => {
    const items: Breadcrumb.Item[] = [
      { href: "/1", label: "サイヤ人編" },
      { href: "/2", label: "ナメック星編" },
      { href: "/3", label: "人造人間編" },
      { href: "/4", currentPage: true, label: "魔人ブウ編" },
    ]

    await render(
      <Breadcrumb.Root endBoundaries={1} items={items} startBoundaries={1} />,
    )

    const listItems = page.getByRole("listitem")

    expect(listItems).toHaveLength(5)
    await expect
      .element(listItems.nth(0).getByRole("link"))
      .toHaveAttribute("href", "/1")
    await expect
      .element(listItems.nth(4).getByText("魔人ブウ編"))
      .toHaveAttribute("aria-current", "page")
  })

  test("if boundaries is 0 or undefined, 1 is correctly reflected.", async () => {
    const items: Breadcrumb.Item[] = [
      { href: "/1", label: "サイヤ人編" },
      { href: "/2", label: "ナメック星編" },
      { href: "/3", label: "人造人間編" },
      { href: "/4", currentPage: true, label: "魔人ブウ編" },
    ]

    await render(
      <Breadcrumb.Root
        data-testid="breadCrumb1"
        items={items}
        startBoundaries={1}
      />,
    )

    await render(
      <Breadcrumb.Root
        data-testid="breadCrumb2"
        endBoundaries={1}
        items={items}
      />,
    )

    await render(
      <Breadcrumb.Root
        data-testid="breadCrumb3"
        endBoundaries={0}
        items={items}
        startBoundaries={0}
      />,
    )

    expect(page.getByTestId("breadCrumb1").getByRole("listitem")).toHaveLength(
      3,
    )
    expect(page.getByTestId("breadCrumb2").getByRole("listitem")).toHaveLength(
      3,
    )
    expect(page.getByTestId("breadCrumb3").getByRole("listitem")).toHaveLength(
      7,
    )
  })

  test("applies custom `aria-label` to the nav element", async () => {
    await render(
      <Breadcrumb.Root aria-label="Custom Breadcrumb" data-testid="root">
        <Breadcrumb.Link href="/">Link 1</Breadcrumb.Link>
        <Breadcrumb.Link href="/" currentPage>
          Link 2
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )

    await expect
      .element(page.getByTestId("root"))
      .toHaveAttribute("aria-label", "Custom Breadcrumb")
  })

  test("ellipsis respects `aria-hidden` override", async () => {
    await render(
      <Breadcrumb.Root>
        <Breadcrumb.Link href="/">Link 1</Breadcrumb.Link>
        <Breadcrumb.Ellipsis aria-hidden={false} data-testid="ellipsis" />
        <Breadcrumb.Link href="/" currentPage>
          Link 2
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )

    await expect
      .element(page.getByTestId("ellipsis"))
      .toHaveAttribute("aria-hidden", "false")
  })

  test("ellipsis respects `tabIndex` override", async () => {
    await render(
      <Breadcrumb.Root>
        <Breadcrumb.Link href="/">Link 1</Breadcrumb.Link>
        <Breadcrumb.Ellipsis data-testid="ellipsis" tabIndex={-1} />
        <Breadcrumb.Link href="/" currentPage>
          Link 2
        </Breadcrumb.Link>
      </Breadcrumb.Root>,
    )

    await expect
      .element(page.getByTestId("ellipsis"))
      .toHaveAttribute("tabindex", "-1")
  })

  test("retrieve omitted items correctly", async () => {
    const ellipsis = vi.fn()

    const items: Breadcrumb.Item[] = [
      { href: "/", label: "サイヤ人編" },
      { href: "/", label: "ナメック星編" },
      { href: "/", label: "人造人間編" },
      { href: "/", currentPage: true, label: "魔人ブウ編" },
    ]

    await render(
      <Breadcrumb.Root
        ellipsis={ellipsis}
        endBoundaries={1}
        items={items}
        startBoundaries={1}
      />,
    )

    expect(ellipsis).toHaveBeenCalledExactlyOnceWith({
      items: [
        { href: "/", label: "ナメック星編" },
        { href: "/", label: "人造人間編" },
      ],
    })
  })
})

"use client"

import type { ReactElement } from "react"
import type { HTMLStyledProps, PropGetter, ThemeProps } from "@yamada-ui/react"
import type { BreadcrumbStyle } from "./breadcrumb.style"
import type { UseBreadcrumbProps } from "./use-breadcrumb"
import { Fragment, useMemo } from "react"
import { createSlotComponent, styled } from "@yamada-ui/react"
import { ChevronRightIcon, EllipsisIcon } from "../icon"
import { breadcrumbStyle } from "./breadcrumb.style"
import { useBreadcrumb } from "./use-breadcrumb"

interface ComponentContext {
  getEllipsisProps: PropGetter<"svg">
  getLinkProps: PropGetter<"a", { currentPage?: boolean }>
}

export interface BreadcrumbRootProps
  extends
    HTMLStyledProps<"nav">,
    ThemeProps<BreadcrumbStyle>,
    Omit<UseBreadcrumbProps, "endBoundaries" | "startBoundaries"> {
  /**
   * Number of elements visible on the end(right) edges.
   *
   * @default 0
   */
  endBoundaries?: number
  /**
   * The visual separator between each breadcrumb item.
   *
   * @default '/'
   */
  separator?: ReactElement | string
  /**
   * Number of elements visible on the start(left) edges.
   *
   * @default 0
   */
  startBoundaries?: number
  /**
   * Props for item element.
   */
  itemProps?: BreadcrumbItemProps
  /**
   * Props for ol element.
   */
  listProps?: HTMLStyledProps<"ol">
  /**
   * Props for separator element.
   */
  separatorProps?: BreadcrumbSeparatorProps
}

const {
  ComponentContext,
  PropsContext: BreadcrumbPropsContext,
  useComponentContext,
  usePropsContext: useBreadcrumbPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<BreadcrumbRootProps, BreadcrumbStyle, ComponentContext>(
  "breadcrumb",
  breadcrumbStyle,
)

export { BreadcrumbPropsContext, useBreadcrumbPropsContext }

/**
 * `Breadcrumb` is a component that helps users understand the hierarchy of a website.
 *
 * @see https://yamada-ui.com/docs/components/breadcrumb
 */
export const BreadcrumbRoot = withProvider<"nav", BreadcrumbRootProps>(
  ({
    endBoundaries,
    gap,
    separator,
    startBoundaries,
    itemProps,
    listProps,
    separatorProps,
    ...rest
  }) => {
    const {
      children,
      getEllipsisProps,
      getLinkProps,
      getListProps,
      getRootProps,
    } = useBreadcrumb({
      ellipsis: <BreadcrumbEllipsis />,
      endBoundaries,
      link: <BreadcrumbLink />,
      startBoundaries,
      ...rest,
    })

    const context = useMemo(
      () => ({ getEllipsisProps, getLinkProps }),
      [getEllipsisProps, getLinkProps],
    )

    return (
      <ComponentContext value={context}>
        <styled.nav {...getRootProps()}>
          <BreadcrumbList {...getListProps({ gap, ...listProps })}>
            {children.map((child, index) => {
              const last = index === children.length - 1

              return (
                <Fragment key={index}>
                  <BreadcrumbItem {...itemProps}>{child}</BreadcrumbItem>

                  {!last ? (
                    <BreadcrumbSeparator {...separatorProps}>
                      {separator}
                    </BreadcrumbSeparator>
                  ) : null}
                </Fragment>
              )
            })}
          </BreadcrumbList>
        </styled.nav>
      </ComponentContext>
    )
  },
  "root",
)()

interface BreadcrumbListProps extends HTMLStyledProps<"ol"> {}

const BreadcrumbList = withContext<"ol", BreadcrumbListProps>("ol", "list")()

interface BreadcrumbItemProps extends HTMLStyledProps<"li"> {}

const BreadcrumbItem = withContext<"li", BreadcrumbItemProps>("li", "item")()

interface BreadcrumbSeparatorProps extends HTMLStyledProps<"li"> {}

const BreadcrumbSeparator = withContext<"li", BreadcrumbSeparatorProps>(
  BreadcrumbItem,
  "separator",
)(({ children, ...rest }) => ({
  children: children ?? <ChevronRightIcon />,
  ...rest,
}))

export interface BreadcrumbLinkProps extends HTMLStyledProps<"a"> {
  /**
   * If `true`, change to span element.
   *
   * @default false
   */
  currentPage?: boolean
}

export const BreadcrumbLink = withContext<"a", BreadcrumbLinkProps>(
  "a",
  "link",
)(undefined, ({ currentPage, ...rest }) => {
  const { getLinkProps } = useComponentContext()

  return {
    as: !currentPage ? "a" : "span",
    ...getLinkProps({ currentPage, ...rest }),
  }
})

export interface BreadcrumbEllipsisProps extends HTMLStyledProps<"svg"> {}

export const BreadcrumbEllipsis = withContext<"svg", BreadcrumbEllipsisProps>(
  EllipsisIcon,
  "ellipsis",
)(undefined, (props) => {
  const { getEllipsisProps } = useComponentContext()

  return { ...getEllipsisProps(props) }
})

export {
  BreadcrumbEllipsis as Ellipsis,
  BreadcrumbLink as Link,
  BreadcrumbPropsContext as PropsContext,
  BreadcrumbRoot as Root,
  useBreadcrumbPropsContext as usePropsContext,
} from "./breadcrumb"
export type {
  BreadcrumbEllipsisProps as EllipsisProps,
  BreadcrumbLinkProps as LinkProps,
  BreadcrumbRootProps as RootProps,
} from "./breadcrumb"
export type { BreadcrumbItem as Item } from "./use-breadcrumb"

"use client"

import type { ReactElement, ReactNode } from "react"
import type {
  HTMLProps,
  PropGetter,
  ReactNodeOrFunction,
} from "@yamada-ui/react"
import { cloneElement, useCallback, useMemo } from "react"
import { mergeProps, runIfFn, useValidChildren } from "@yamada-ui/react"
import { useI18n } from "../../providers/i18n-provider"

export interface BreadcrumbItem extends HTMLProps<"a"> {
  currentPage?: boolean
  label?: ReactNode
}

export interface UseBreadcrumbProps extends HTMLProps<"nav"> {
  /**
   * The icon to be used in the ellipsis.
   */
  ellipsis?: ReactNodeOrFunction<{ items: BreadcrumbItem[] }>
  /**
   * Number of elements visible on the end(right) edges.
   *
   * @default 0
   */
  endBoundaries?: number
  /**
   * If provided, generate breadcrumb items based on items.
   */
  items?: BreadcrumbItem[]
  /**
   * The component to be used for the link.
   */
  link?: ReactElement<any>
  /**
   * Number of elements visible on the start(left) edges.
   *
   * @default 0
   */
  startBoundaries?: number
}

export const useBreadcrumb = ({
  children,
  ellipsis,
  endBoundaries = 0,
  items = [],
  link,
  startBoundaries = 0,
  ...rest
}: UseBreadcrumbProps = {}) => {
  const validChildren = useValidChildren(children)
  const length = validChildren.length || items.length
  const { t } = useI18n("breadcrumb")

  const hasBoundaries =
    startBoundaries + endBoundaries > 0 &&
    length > startBoundaries + endBoundaries

  const renderLink = useCallback(
    (items: BreadcrumbItem[]) => {
      if (!link) return []

      return items.map(({ label, ...rest }) =>
        cloneElement<any>(link, { ...link.props, children: label, ...rest }),
      )
    },
    [link],
  )

  const renderEllipsis = useCallback(
    (items: BreadcrumbItem[]) => {
      if (!ellipsis) return null

      return runIfFn(ellipsis, { items })
    },
    [ellipsis],
  )

  const splitItems = useCallback(
    (items: BreadcrumbItem[]) => {
      const length = items.length
      const firstItems = items.slice(0, startBoundaries)
      const ellipsisItems = items.slice(startBoundaries, length - endBoundaries)
      const lastItems = items.slice(length - endBoundaries)

      return [firstItems, ellipsisItems, lastItems] as const
    },
    [startBoundaries, endBoundaries],
  )

  const cloneChildren = useMemo(() => {
    const hasChildren = !!validChildren.length

    if (hasChildren) {
      return validChildren
    } else if (hasBoundaries) {
      const [firstItems, ellipsisItems, lastItems] = splitItems(items)

      return [
        ...renderLink(firstItems),
        renderEllipsis(ellipsisItems),
        ...renderLink(lastItems),
      ]
    } else {
      return renderLink(items)
    }
  }, [
    validChildren,
    items,
    hasBoundaries,
    renderEllipsis,
    renderLink,
    splitItems,
  ])

  const getRootProps: PropGetter<"nav"> = useCallback(
    (props) => mergeProps({ "aria-label": t("Breadcrumb") }, rest, props)(),
    [rest, t],
  )

  const getListProps: PropGetter<"ol"> = useCallback(
    (props) => ({ ...props }),
    [],
  )

  const getLinkProps: PropGetter<"a", { currentPage?: boolean }> = useCallback(
    ({ href, currentPage, ...props } = {}) => ({
      href: !currentPage ? href : undefined,
      "aria-current": currentPage ? "page" : undefined,
      ...props,
    }),
    [],
  )

  const getEllipsisProps: PropGetter<"svg"> = useCallback(
    (props) => ({
      "aria-label": t("Ellipsis"),
      role: "presentation",
      ...props,
    }),
    [t],
  )

  return {
    children: cloneChildren,
    getEllipsisProps,
    getLinkProps,
    getListProps,
    getRootProps,
  }
}

export type UseBreadcrumbReturn = ReturnType<typeof useBreadcrumb>
